function maximumGoodPeople(statements) {
    const n = statements.length;
    let count_good = 0;
    for(let i = 0; i < n; i++) {
        let is_good = true;
        for(let j = 0; j < n; j++) {
            if(statements[j][i] === 1 && statements[i][j] === 0) {
                is_good = false;
                break;
            }
        }
        if(is_good) count_good++;
    }
    return count_good;
}
```


